"use client";

import { useMemo, useRef, useState } from "react";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";

interface PhotoWidgetProps {
  photos: any[];
  onUpload: (imageData: string, caption?: string) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
  userId: string;
  partnerName?: string;
}

export function PhotoWidget({ photos, onUpload, onDelete, userId, partnerName }: PhotoWidgetProps) {
  const [caption, setCaption] = useState("");
  const [uploading, setUploading] = useState(false);
  const [expanded, setExpanded] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const displayPhoto = useMemo(() => {
    const partnerLatest = photos.find((p) => p.authorId !== userId);
    return partnerLatest || photos[0] || null;
  }, [photos, userId]);

  async function handleFile(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 10 * 1024 * 1024) {
      alert("Image must be under 10MB");
      return;
    }

    setUploading(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const dataUri = reader.result as string;
      await onUpload(dataUri, caption || undefined);
      setCaption("");
      setUploading(false);
      setExpanded(false);
      if (fileRef.current) fileRef.current.value = "";
    };
    reader.readAsDataURL(file);
  }

  return (
    <div className="h-full flex flex-col">
      <div className="flex items-center justify-between mb-3">
        <h3 className="text-base font-bold text-gray-600 dark:text-slate-200 uppercase tracking-wider">Photos</h3>
