  { value: "NEUTRAL", Component: IceCream, color: "#bbf7d0", label: "Chill", mood: "happy" },
];

interface CheckInWidgetProps {
  recentCheckIns: any[];
  onCheckIn: (mood: string, message?: string) => Promise<void>;
}

