            {(() => {
              const m = MOODS.find((it) => it.value === selected);
              if (!m) return null;
              const C = m.Component;
              return <C size={70} mood={m.mood as any} color={m.color} />;
            })()}
            <p className="text-sm text-gray-600 dark:text-slate-200">Checked in!</p>
            <button
              onClick={() => {
                setSubmitted(false);
                setSelected(null);
                setMessage("");
