              className="text-xs text-gray-500 dark:text-slate-300 hover:text-gray-700 dark:hover:text-slate-100 transition-colors mt-1"
            >
              Change
            </button>
          </motion.div>
        ) : (
          <motion.div key="form" className="flex-1 flex flex-col">
            <div className="grid grid-cols-2 gap-2.5 mb-3">
              {MOODS.map((m) => {
                const C = m.Component;
                return (
                  <motion.button
                    key={m.value}
                    onClick={() => setSelected(m.value)}
                    whileTap={{ scale: 0.95 }}
                    className={`flex flex-col items-center py-3 rounded-xl text-sm transition-all border ${
                      selected === m.value
                        ? "ring-2 ring-love-300 dark:ring-lavender-300 shadow-sm border-love-200 dark:border-lavender-400"
                        : "border-transparent hover:bg-gray-50 dark:hover:bg-slate-800"
                    }`}
                    style={{ backgroundColor: selected === m.value ? `${m.color}44` : "transparent" }}
                  >
                    <C size={44} mood={m.mood as any} color={m.color} />
                    <span className="text-sm text-gray-700 dark:text-slate-100 mt-1">{m.label}</span>
                  </motion.button>
                );
              })}
            </div>

            {selected && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: "auto" }} className="space-y-2">
                <input
                  type="text"
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  placeholder="A little note... (optional)"
                  className="w-full text-sm px-3 py-2 rounded-xl border border-gray-200 dark:border-slate-600 bg-white dark:bg-slate-900 focus:outline-none focus:ring-1 focus:ring-love-300 placeholder:text-gray-400 dark:placeholder:text-slate-500"
                  maxLength={140}
                />
                <button onClick={handleSubmit} disabled={sending} className="w-full text-sm font-semibold py-2 rounded-xl bg-love-400 text-white hover:bg-love-500 transition-colors disabled:opacity-50">
                  {sending ? "..." : "Check in"}
                </button>
              </motion.div>
            )}

            {partnerMoodDef && partnerCheckIn && (
              <div className="mt-auto pt-3 border-t border-gray-100 dark:border-slate-700">
                <div className="flex items-center gap-2">
                  <partnerMoodDef.Component size={34} mood={partnerMoodDef.mood as any} color={partnerMoodDef.color} />
                  <div>
                    <p className="text-sm font-medium text-gray-700 dark:text-slate-100">
                      {partnerCheckIn.author?.name} is feeling {partnerMoodDef.label.toLowerCase()}
                    </p>
                    {partnerCheckIn.message && (
                      <p className="text-xs text-gray-500 dark:text-slate-300 mt-0.5">&ldquo;{partnerCheckIn.message}&rdquo;</p>
                    )}
                  </div>
                </div>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
