            <span className="text-xs text-gray-600 dark:text-slate-100 w-7 text-right">{stat.value}</span>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-3 gap-2 w-full">
        {actions.map((a) => (
          <button
            key={a.type}
            onClick={() => handleAction(a.type)}
            disabled={acting}
            className="flex flex-col items-center gap-1 py-2 rounded-xl bg-white dark:bg-slate-800 border border-gray-100 dark:border-slate-700 hover:border-love-200 dark:hover:border-lavender-300 hover:bg-love-50/50 dark:hover:bg-slate-700 transition-all active:scale-95 disabled:opacity-40"
          >
            <img src={a.iconPath} alt={a.label} className="w-7 h-7" />
            <span className="text-xs font-semibold text-gray-700 dark:text-slate-100">{a.label}</span>
          </button>
        ))}
      </div>
    </div>
