export const CUTE_AVATARS = [
  "avatar-bunny",
  "avatar-bear",
  "avatar-panda",
  "avatar-koala",
  "avatar-fox",
  "avatar-kitty",
  "avatar-puppy",
  "avatar-frog",
  "avatar-hamster",
  "avatar-tiger",
  "avatar-cow",
  "avatar-pig",
  "avatar-unicorn",
  "avatar-chick",
  "avatar-teddy",
  "avatar-blossom",
] as const;

export type CuteAvatar = (typeof CUTE_AVATARS)[number];

const LEGACY_EMOJI_SET = new Set([
  "🐰", "🐻", "🐼", "🐨", "🦊", "🐱", "🐶", "🐸",
  "🐹", "🐯", "🐮", "🐷", "🦄", "🐣", "🧸", "🌸", "💕", "🦋", "🌟",
]);

function normalizeAvatarKey(input: string): string {
  return input
    .trim()
    .toLowerCase()
    .replace(/[–—−]/g, "-")
    .replace(/\s+/g, "-");
}

export function getAvatarImage(avatar: string | null | undefined): string {
  if (!avatar) return "/avatars/avatar-bunny.svg";
  if (LEGACY_EMOJI_SET.has(avatar)) return "/avatars/avatar-bunny.svg";

  const normalized = normalizeAvatarKey(avatar);
  if (normalized.startsWith("avatar-")) {
    return `/avatars/${normalized}.svg`;
  }

  return "/avatars/avatar-bunny.svg";
}
