      </div>

      <div className="flex-1 flex items-center justify-center py-2">
        <motion.div animate={lastAction ? { scale: [1, 1.12, 1] } : { y: [0, -6, 0] }} transition={lastAction ? { duration: 0.3 } : { repeat: Infinity, duration: 3, ease: "easeInOut" }}>
