import { NextRequest } from "next/server";

const PALETTES = [
  { bg: "#FDF2F8", face: "#F472B6", ear: "#BE185D" },
  { bg: "#FFF7ED", face: "#FB923C", ear: "#C2410C" },
  { bg: "#F0FDF4", face: "#22C55E", ear: "#15803D" },
  { bg: "#EFF6FF", face: "#60A5FA", ear: "#1D4ED8" },
  { bg: "#FEF2F2", face: "#EF4444", ear: "#B91C1C" },
  { bg: "#F5F3FF", face: "#A78BFA", ear: "#6D28D9" },
  { bg: "#F0F9FF", face: "#0EA5E9", ear: "#0369A1" },
  { bg: "#F0FDFA", face: "#14B8A6", ear: "#0F766E" },
];

function normalize(input: string): string {
  return input
    .trim()
    .toLowerCase()
    .replace(/\.svg$/i, "")
    .replace(/[–—−]/g, "-")
    .replace(/\s+/g, "-");
}

function hash(str: string): number {
  let h = 0;
  for (let i = 0; i < str.length; i += 1) {
    h = (h << 5) - h + str.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
}

function buildSvg(seed: string): string {
  const p = PALETTES[hash(seed) % PALETTES.length];
  return `<svg width="96" height="96" viewBox="0 0 96 96" xmlns="http://www.w3.org/2000/svg"><rect width="96" height="96" rx="24" fill="${p.bg}"/><circle cx="48" cy="52" r="24" fill="${p.face}"/><circle cx="33" cy="38" r="7" fill="${p.ear}"/><circle cx="63" cy="38" r="7" fill="${p.ear}"/><circle cx="38" cy="50" r="3" fill="#111827"/><circle cx="58" cy="50" r="3" fill="#111827"/><path d="M39 61c2.5 3 5.5 4 9 4s6.5-1 9-4" fill="none" stroke="#111827" stroke-width="3" stroke-linecap="round"/></svg>`;
}

export async function GET(_req: NextRequest, { params }: { params: { slug: string } }) {
  const raw = decodeURIComponent(params.slug || "avatar-bunny.svg");
  const normalized = normalize(raw);
  const seed = normalized.startsWith("avatar-") ? normalized : `avatar-${normalized || "bunny"}`;
  const svg = buildSvg(seed);

  return new Response(svg, {
    status: 200,
    headers: {
      "Content-Type": "image/svg+xml; charset=utf-8",
      "Cache-Control": "public, max-age=604800, immutable",
    },
  });
}
